import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.DAY4Zhxq.js";const u=JSON.parse('{"title":"Settings & Generation Options","description":"","frontmatter":{},"headers":[],"relativePath":"guide/settings.md","filePath":"guide/settings.md"}'),s={name:"guide/settings.md"};function r(d,t,i,l,p,h){return a(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="settings-generation-options" tabindex="-1">Settings &amp; Generation Options <a class="header-anchor" href="#settings-generation-options" aria-label="Permalink to &quot;Settings &amp; Generation Options&quot;">​</a></h1><p>Alpaka Desktop has three layers of settings that apply to every conversation. The highest-priority layer always wins.</p><h2 id="how-settings-interact" tabindex="-1">How Settings Interact <a class="header-anchor" href="#how-settings-interact" aria-label="Permalink to &quot;How Settings Interact&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Per-Chat Options                          HIGHEST PRIORITY     │</span></span>
<span class="line"><span>│  Chat → Advanced Options panel · applies to this conversation   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Per-Model Defaults                        MEDIUM PRIORITY      │</span></span>
<span class="line"><span>│  Models → click model → Edit Defaults · applies when selected   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  Global Defaults                           LOWEST PRIORITY      │</span></span>
<span class="line"><span>│  Settings → Advanced tab · applies to all new conversations     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>Rules:</strong></p><ul><li>Per-model defaults only override parameters you <strong>explicitly set</strong> — unset parameters fall through to Global Defaults.</li><li>Per-chat options are saved in the conversation draft and never affect other conversations.</li><li>The <strong>&quot;Save as model default&quot;</strong> button in the Advanced Options panel promotes the current chat values to Per-Model Defaults.</li></ul><p><strong>Example — Temperature:</strong> Global default: <code>0.8</code> | llama3.2 model default: <code>0.4</code> | This chat: not changed → Ollama receives <strong>0.4</strong></p><p><strong>Example — Stop Sequences:</strong> Global default: <code>[&quot;###&quot;]</code> | Model default: not set | This chat: <code>[&quot;&amp;lt;END&amp;gt;&quot;, &quot;---&quot;]</code> → Ollama receives <strong>[&quot;&lt;END&gt;&quot;, &quot;---&quot;]</strong></p><hr><h2 id="where-to-change-settings" tabindex="-1">Where to Change Settings <a class="header-anchor" href="#where-to-change-settings" aria-label="Permalink to &quot;Where to Change Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What you want</th><th>Where to go</th></tr></thead><tbody><tr><td>Change defaults for all future conversations</td><td><strong>Settings → Advanced</strong> tab</td></tr><tr><td>Change defaults for a specific model</td><td><strong>Models</strong> tab → click the model → <strong>Edit Defaults</strong></td></tr><tr><td>Change options for just this conversation</td><td>Chat panel → <strong>Advanced Options</strong> (⚙ icon)</td></tr><tr><td>Apply a named bundle of settings at once</td><td>Advanced Options panel → <strong>Preset</strong> selector</td></tr></tbody></table><hr><h2 id="parameter-reference" tabindex="-1">Parameter Reference <a class="header-anchor" href="#parameter-reference" aria-label="Permalink to &quot;Parameter Reference&quot;">​</a></h2><h3 id="temperature-sampling" tabindex="-1">Temperature &amp; Sampling <a class="header-anchor" href="#temperature-sampling" aria-label="Permalink to &quot;Temperature &amp; Sampling&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Temperature</td><td>0.0–2.0</td><td>0.8</td><td>Controls randomness. Lower = more deterministic, higher = more creative and varied.</td></tr><tr><td>Top-P</td><td>0.0–1.0</td><td>0.9</td><td>Nucleus sampling. Model only samples from tokens that together sum to this probability mass.</td></tr><tr><td>Top-K</td><td>1–100</td><td>40</td><td>Limits the vocabulary to the K most likely tokens at each step.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Top-P and Top-K are hidden in the Advanced Options panel when <strong>Mirostat</strong> is active — they have no effect while Mirostat controls sampling.</p></div><h3 id="mirostat" tabindex="-1">Mirostat <a class="header-anchor" href="#mirostat" aria-label="Permalink to &quot;Mirostat&quot;">​</a></h3><p>Mirostat is an adaptive sampling algorithm that targets a specific &quot;perplexity&quot; level instead of using fixed Top-P/Top-K cutoffs. It tends to produce more coherent long-form text.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Off</td><td>Standard Top-P / Top-K sampling (default)</td></tr><tr><td>Mirostat 1</td><td>First-generation algorithm</td></tr><tr><td>Mirostat 2</td><td>Improved version — recommended if you want to use Mirostat</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Tau (τ)</td><td>0.0–10.0</td><td>5.0</td><td>Target entropy. Lower = more focused output, higher = more varied.</td></tr><tr><td>Eta (η)</td><td>0.0–1.0</td><td>0.1</td><td>Learning rate — how quickly the algorithm adapts to the target perplexity.</td></tr></tbody></table><h3 id="context-window" tabindex="-1">Context Window <a class="header-anchor" href="#context-window" aria-label="Permalink to &quot;Context Window&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>num_ctx</td><td>512–131072</td><td>model default</td><td>Number of tokens the model sees at once. Larger values support longer conversations but require more VRAM.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Setting <code>num_ctx</code> higher than the model&#39;s trained context length does not improve quality and wastes memory. Check the model&#39;s page on the Ollama library for the recommended value.</p></div><h3 id="repetition-control" tabindex="-1">Repetition Control <a class="header-anchor" href="#repetition-control" aria-label="Permalink to &quot;Repetition Control&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Repeat penalty</td><td>0.0–2.0</td><td>1.1</td><td>Penalises recently used tokens. Values above 1.0 discourage repetition; values below 1.0 encourage it.</td></tr><tr><td>Repeat last N</td><td>0–512</td><td>64</td><td>How many previous tokens to check when applying the repeat penalty.</td></tr></tbody></table><h3 id="stop-sequences" tabindex="-1">Stop Sequences <a class="header-anchor" href="#stop-sequences" aria-label="Permalink to &quot;Stop Sequences&quot;">​</a></h3><p>Custom tokens that signal the model to stop generating. Useful for structured outputs or prompt-chaining.</p><ul><li>Configure up to 4 stop tokens in <strong>Settings → Advanced → Stop Sequences</strong> (global) or in <strong>Advanced Options</strong> (per-chat).</li><li>Common examples: <code>###</code>, <code>&amp;lt;END&amp;gt;</code>, <code>\\n\\n</code>, <code>Human:</code>.</li><li>An empty list omits the <code>stop</code> field entirely — the model generates until its natural end token.</li></ul><h3 id="seed" tabindex="-1">Seed <a class="header-anchor" href="#seed" aria-label="Permalink to &quot;Seed&quot;">​</a></h3><p>A fixed seed makes generation reproducible — the same prompt with the same model and the same seed always produces the same output.</p><ul><li>Set in <strong>Advanced Options → Seed</strong> (per-chat) or <strong>Settings → Advanced → Seed</strong> (global default).</li><li>When a fixed seed is active, the seed value appears in the <strong>message performance metadata</strong> row (the tokens/s line below each response).</li><li>Set to <code>-1</code> or leave blank for random generation each time.</li></ul><h3 id="system-prompt" tabindex="-1">System Prompt <a class="header-anchor" href="#system-prompt" aria-label="Permalink to &quot;System Prompt&quot;">​</a></h3><p>A system-level instruction prepended to every conversation. The model sees it before your first message.</p><ul><li>Set per-conversation in the <strong>System Prompt</strong> field at the top of the chat panel.</li><li>Stored as a <code>system</code> role message in SQLite.</li><li>System prompts are always per-conversation — they are not affected by model defaults or global settings.</li></ul><h3 id="preset-profiles" tabindex="-1">Preset Profiles <a class="header-anchor" href="#preset-profiles" aria-label="Permalink to &quot;Preset Profiles&quot;">​</a></h3><p>Presets are named bundles of generation settings you can apply with one click from the Advanced Options panel.</p><p><strong>Built-in presets:</strong></p><table tabindex="0"><thead><tr><th>Preset</th><th>Temperature</th><th>Top-P</th><th>Best for</th></tr></thead><tbody><tr><td>Creative</td><td>1.2</td><td>0.95</td><td>Brainstorming, fiction, open-ended questions</td></tr><tr><td>Balanced</td><td>0.8</td><td>0.9</td><td>General-purpose chat</td></tr><tr><td>Precise</td><td>0.2</td><td>0.7</td><td>Factual questions, structured data, code review</td></tr><tr><td>Code</td><td>0.1</td><td>0.85</td><td>Code generation and completion</td></tr></tbody></table><p><strong>User-defined presets:</strong></p><ul><li>Save your current Advanced Options values as a named preset using the <strong>Save preset</strong> button.</li><li>Delete presets you no longer need via the preset menu.</li><li>The active preset name is shown in the Advanced Options panel header.</li><li>Presets are persisted per-conversation in the draft — switching conversations restores that conversation&#39;s preset selection.</li></ul>`,40)])])}const m=e(s,[["render",r]]);export{u as __pageData,m as default};
